// ==========================================================================
// DEVELOPER (real-agent mode) — picks one To Do task and ships a PR to develop.
// Instead of writing files blindly via the GitHub API, it delegates the actual
// coding to the bridge's POST /code-task: the bridge clones the repo on the Mac,
// runs the active CLI engine (claude/agy) *inside* the checkout with full tools
// (Read/Edit/Write/Bash/Grep) + auto-approve, then commits & pushes task/<cardId>.
// This node stays pure orchestration: pick card -> build the agent brief ->
// call /code-task -> open the PR -> write docs -> release Waiting-API deps ->
// move card to In Review + notify + trigger WF3.
// If the task branch already exists it is a returning bug -> fix mode (the agent
// patches the real working tree instead of rewriting from scratch).
// ==========================================================================

const TK = $env.TRELLO_KEY, TT = $env.TRELLO_TOKEN, BOARD = $env.TRELLO_BOARD_ID;
const L = {
  todo: $env.TRELLO_LIST_TODO,
  prog: $env.TRELLO_LIST_INPROGRESS,
  wait: $env.TRELLO_LIST_WAITING,
  review: $env.TRELLO_LIST_INREVIEW,
  owner: $env.TRELLO_LIST_OWNER,
};
const GHTOKEN = $env.GITHUB_TOKEN, OWNER_CHAT = $env.OWNER_CHAT, BALE = $env.BALE_BOT_TOKEN;
const BRIDGE = 'http://host.docker.internal:8787';
const CLAUDE_BRIDGE = BRIDGE + '/v1/messages';
const CODE_TASK = BRIDGE + '/code-task';
const req = (o) => this.helpers.httpRequest(o);
const tUrl = (p) => 'https://api.trello.com/1/' + p + (p.includes('?') ? '&' : '?') + 'key=' + TK + '&token=' + TT;
const tGet = async (p) => { try { return await req({ method: 'GET', url: tUrl(p), json: true }); } catch (e) { return []; } };
const tPost = async (p) => req({ method: 'POST', url: tUrl(p), json: true });
const tPut = async (p) => req({ method: 'PUT', url: tUrl(p), json: true });
const bale = async (chat, text) => {
  try {
    await req({ method: 'POST', url: 'https://tapi.bale.ai/bot' + BALE + '/sendMessage', body: JSON.stringify({ chat_id: chat, text }), headers: { 'content-type': 'application/json' }, json: false });
  } catch (e) {}
};
const claude = async (prompt, mt) => {
  const r = await req({ method: 'POST', url: CLAUDE_BRIDGE, body: JSON.stringify({ model: 'claude-opus-4-8', max_tokens: mt || 3000, messages: [{ role: 'user', content: prompt }] }), headers: { 'content-type': 'application/json' }, json: false });
  const j = typeof r === 'string' ? JSON.parse(r) : r;
  return (j.content && j.content[0] && j.content[0].text) || '';
};
const enc = (s) => Buffer.from(s || '', 'utf8').toString('base64');
const normRepo = (u) => String(u || '').trim().replace(/\.git$/, '').replace(/^https?:\/\/github\.com\//i, '').replace(/^github\.com\//i, '');
const gh = async (method, path, body, raw) => {
  const r = await req({ method, url: 'https://api.github.com' + path, headers: { Authorization: 'Bearer ' + GHTOKEN, Accept: raw ? 'application/vnd.github.raw+json' : 'application/vnd.github+json', 'User-Agent': 'n8n-bot' }, body: body ? JSON.stringify(body) : undefined, json: false });
  if (raw) return typeof r === 'string' ? r : JSON.stringify(r);
  try { return typeof r === 'string' ? JSON.parse(r) : r; } catch (e) { return r; }
};
const meta = (d) => {
  d = String(d || '');
  const g = (re) => { const m = d.match(re); return m ? m[1].trim() : ''; };
  return { repo: normRepo(g(/repo:\s*(\S+)/)), project: g(/project:\s*(.+)/), ref: g(/ref:\s*(\S+)/), clone: g(/clone:\s*(\S+)/) };
};
const trackOf = (name) => { const m = String(name || '').match(/^\[(backend|frontend|mobile)\]/); return m ? m[1] : 'backend'; };

// Each platform stack is read from stacks/<track>.md (served by claude-bridge.js),
// falling back to the built-in default so the system never stalls.
const STACK_DEFAULT = {
  backend: 'نقش: Backend Developer. استک: Python + Django + Django REST Framework با معماری تمیز. کل کد زیر پوشه‌ی backend/ و یک پکیج کامل و قابل‌اجرا. حداقل ۳ unit test با pytest در backend/ بنویس.',
  frontend: 'نقش: Frontend Developer. استک: Angular (standalone، TypeScript، RxJS). کل کد زیر پوشه‌ی frontend/ و package.json با اسکریپت test. حداقل ۳ unit test بنویس.',
  mobile: 'نقش: Mobile Developer. استک: Kotlin Multiplatform + Compose. کل کد زیر پوشه‌ی mobile/ با Gradle. حداقل ۳ unit test (kotlin.test) بنویس.',
};
const readStack = async (t) => {
  try { const s = await req({ method: 'GET', url: BRIDGE + '/stack/' + t, json: false }); const v = String(s || '').trim(); return v || STACK_DEFAULT[t]; } catch (e) { return STACK_DEFAULT[t]; }
};
const readRole = async (role) => {
  try { const s = await req({ method: 'GET', url: BRIDGE + '/role/' + role, json: false }); return String(s || '').trim(); } catch (e) { return ''; }
};

// ---- pick exactly one task (backend first), respecting the one-in-flight rule
let todo = await tGet('lists/' + L.todo + '/cards?fields=name,desc');
todo = todo.filter((c) => c && c.id);
if (!todo.length) return [{ json: { idle: 1 } }];
const inProg = await tGet('lists/' + L.prog + '/cards?fields=id');
const inRev = await tGet('lists/' + L.review + '/cards?fields=id');
if (inProg.length || inRev.length) return [{ json: { idle: 1, reason: 'task in flight' } }];
todo.sort((a, b) => (trackOf(a.name) === 'backend' ? 0 : 1) - (trackOf(b.name) === 'backend' ? 0 : 1));
const c = todo[0];
const mm = meta(c.desc);
if (!mm.repo) { await tPut('cards/' + c.id + '?idList=' + L.review); return [{ json: { noRepo: c.id } }]; }
const [o, r] = mm.repo.split('/');
const track = trackOf(c.name);
const dir = track + '/';
await tPut('cards/' + c.id + '?idList=' + L.prog);
const branch = 'task/' + c.id;

// fix mode: the task branch already exists -> this card came back for a bug fix
let isFix = false;
try { await gh('GET', '/repos/' + o + '/' + r + '/git/ref/heads/' + branch); isFix = true; } catch (e) {}
let failLog = '';
if (isFix) {
  try {
    const acts = await tGet('cards/' + c.id + '/actions?filter=commentCard&limit=6');
    failLog = (acts || []).map((a) => a && a.data && a.data.text).filter(Boolean).slice(0, 3).join('\n----\n');
  } catch (e) {}
}
// API docs for front/mobile so the agent matches the backend contract
let apiDocs = '';
if (track !== 'backend') {
  try { apiDocs = await gh('GET', '/repos/' + o + '/' + r + '/contents/docs/api/API.md?ref=develop', null, true); } catch (e) {}
}

// ---- build the agent brief (instructions, NOT a JSON-files request) -------
const stackText = await readStack(track);
const devRole = (await readRole('developer')) || '';
const base = (devRole ? devRole + '\n\n' : '') + stackText + '\nنام پروژه: ' + (mm.project || '') + (mm.ref ? '\nمرجع: ' + mm.ref : '') + '\nهمه‌ی کد باید زیر پوشه‌ی ' + dir + ' باشد.' + (apiDocs ? '\n\nمستندات API:\n' + apiDocs : '');
const workRules = '\n\nتو داخل یک checkout گیت از پروژه کار می‌کنی و به ابزارهای Read/Grep/Edit/Write/Bash دسترسی کامل داری. قبل از نوشتن، فایل‌های همسایه را بخوان تا از قراردادها و ساختار موجود پیروی کنی. همه‌ی کد و تست‌ها باید زیر ' + dir + ' باشند؛ به پوشه‌ی track‌های دیگر دست نزن. طبق استک حداقل ۳ تست واقعی (نه فقط happy-path) بنویس. کد تمیز و قابل‌اجرا تحویل بده.\n\n⚙️ قبل از پایان، تست‌ها را همان‌جا با Bash لوکال اجرا کن (مثلاً pytest/npm test/gradle test متناسب با استک) و فقط وقتی سبز شدند کار را تمام کن؛ اگر قرمز بودند خودت رفعشان کن. (CI گیت‌هاب منبع نهایی است، ولی تست لوکال لوپ را سریع‌تر می‌کند.) وقتی کار تمام شد متوقف شو.';
const prompt = isFix
  ? base + workRules + '\n\n⚠️ این تسک قبلاً پیاده‌سازی شده بود ولی باگ یا خطای build/test داشت و برگشت. کد فعلی همین حالا در working tree موجود است؛ آن را بخوان، ریشه‌ی مشکل را پیدا کن و فقط همان را رفع کن — از صفر بازنویسی نکن.\n\nخطاها/دلیل برگشت:\n' + (failLog || '(نامشخص — کد را بازبینی و مشکلات احتمالی build/test را رفع کن)') + '\n\nتسک:\n' + c.name + '\n' + c.desc
  : base + workRules + '\n\nتسک:\n' + c.name + '\n' + c.desc;

// ---- delegate the actual coding to the bridge (clone + real agent + push) -
let ct;
try {
  const rr = await req({ method: 'POST', url: CODE_TASK, body: JSON.stringify({ repo: mm.repo, cloneUrl: mm.clone || '', branch, track, task: prompt, message: (isFix ? 'fix: ' : 'feat: ') + c.name }), headers: { 'content-type': 'application/json' }, json: false, timeout: 1500000 });
  ct = typeof rr === 'string' ? JSON.parse(rr) : rr;
} catch (e) { ct = { ok: false, error: (e && e.message) || String(e) }; }

if (!ct || !ct.ok) {
  await bale(OWNER_CHAT, '⚠️ اجرای تسک ناموفق: ' + c.name + '\n' + ((ct && ct.error) || '') + '\n(کارت به To Do برگشت)');
  await tPut('cards/' + c.id + '?idList=' + L.todo);
  return [{ json: { codeTaskErr: c.id, error: (ct && ct.error) || '' } }];
}
if (!ct.committed) {
  await bale(OWNER_CHAT, '⚠️ agent تغییری اعمال نکرد روی: ' + c.name + (ct.noChanges ? ' (no changes)' : '') + '\n(کارت به To Do برگشت)');
  await tPut('cards/' + c.id + '?idList=' + L.todo);
  return [{ json: { noChanges: c.id } }];
}

// ---- open (or reuse) the PR to develop -----------------------------------
let pr;
try {
  pr = await gh('POST', '/repos/' + o + '/' + r + '/pulls', { title: c.name, head: branch, base: 'develop', body: 'Trello: ' + c.id + '\nTrack: ' + track + '\nFiles: ' + (ct.filesChanged || []).slice(0, 20).join(', ') + '\n\n' + (c.desc || '') });
} catch (e) {
  // a PR for this branch may already be open (fix mode reusing the branch)
  try { const ex = await gh('GET', '/repos/' + o + '/' + r + '/pulls?head=' + o + ':' + branch + '&state=open'); pr = (ex && ex[0]) || null; } catch (e2) {}
  if (!pr) {
    await bale(OWNER_CHAT, '⚠️ ساخت PR ناموفق برای ' + c.name + ': ' + ((e && e.message) || ''));
    await tPut('cards/' + c.id + '?idList=' + L.todo);
    return [{ json: { prErr: c.id } }];
  }
}
if (isFix) {
  try {
    const chg = (ct.filesChanged || []).slice(0, 12).join('، ');
    await tPost('cards/' + c.id + '/actions/comments?text=' + encodeURIComponent('🛠️ فیکس اعمال شد (PR #' + pr.number + '). فایل‌های تغییریافته: ' + (chg || '-')));
  } catch (e) {}
}

// ---- documentation (per-task; backend also appends to docs/api/API.md) ----
let docText = '';
try {
  docText = await claude('برای این تسک یک مستند Markdown بنویس. اگر backend است مستند API کامل (هر endpoint با method/مسیر/نمونه request/response). فقط Markdown. تسک: ' + c.name + '\n' + c.desc, 2500);
} catch (e) {}
const docPath = 'docs/' + track + '/' + c.id + '.md';
try {
  let sha;
  try { const ex = await gh('GET', '/repos/' + o + '/' + r + '/contents/' + docPath + '?ref=develop'); sha = ex.sha; } catch (e) {}
  await gh('PUT', '/repos/' + o + '/' + r + '/contents/' + docPath, { message: 'docs: ' + c.name, content: enc(docText || '(بدون مستند)'), branch: 'develop', sha });
} catch (e) {}
if (track === 'backend') {
  try {
    const apiP = 'docs/api/API.md';
    let prev = '', apiSha;
    try { const ex = await gh('GET', '/repos/' + o + '/' + r + '/contents/' + apiP + '?ref=develop'); apiSha = ex.sha; prev = Buffer.from(ex.content, 'base64').toString('utf8'); } catch (e) {}
    const merged = (prev ? prev + '\n\n' : '# API Documentation\n\n') + '## ' + c.name + '\n\n' + docText;
    await gh('PUT', '/repos/' + o + '/' + r + '/contents/' + apiP, { message: 'docs(api): ' + c.name, content: enc(merged), branch: 'develop', sha: apiSha });
    const left = [
      ...(await tGet('lists/' + L.todo + '/cards?fields=name')),
      ...(await tGet('lists/' + L.prog + '/cards?fields=name')),
    ].filter((x) => trackOf(x.name) === 'backend' && x.id !== c.id).length;
    if (left === 0) {
      const w = await tGet('lists/' + L.wait + '/cards?fields=id');
      for (const wc of w) { await tPut('cards/' + wc.id + '?idList=' + L.todo); }
    }
  } catch (e) {}
}

// ---- hand off to review --------------------------------------------------
await tPut('cards/' + c.id + '?idList=' + L.review);
await bale(OWNER_CHAT, (isFix ? '🔧 فیکس شد و رفت برای ریویو: ' : '👀 رفت برای ریویو: ') + c.name + '\nPR: ' + pr.html_url + '\nفایل‌ها: ' + (ct.filesChanged || []).length);
const WF3_HOOK = 'http://localhost:5678/webhook/tech-lead-review';
try { await req({ method: 'POST', url: WF3_HOOK, body: JSON.stringify({ cardId: c.id, prNum: pr.number }), headers: { 'content-type': 'application/json' }, json: false }); } catch (e) {}
return [{ json: { pr: pr.number, card: c.id, track, files: (ct.filesChanged || []).length, isFix } }];
